const ctx = $('Obtener Contexto Negocio').item.json;
const userMsg = $('Webhook ManyChat').item.json.body.last_input_text || '';

const systemPrompt = `Eres el asistente virtual de ${ctx.negocio.nombre}, empresa de banquetería y repostería chilena. Responde siempre en español, de forma amable y concisa (máximo 3 oraciones). Si preguntan por disponibilidad de fechas, consulta las fechas ocupadas y responde si la fecha está disponible o no. Si preguntan por productos o precios, menciona las opciones relevantes con precio en pesos chilenos. Siempre ofrece cotizar por este canal.

INFO DEL NEGOCIO: ${JSON.stringify(ctx.negocio)}

PRODUCTOS DISPONIBLES: ${JSON.stringify(ctx.productos)}

FECHAS OCUPADAS próximos 60 días: ${JSON.stringify(ctx.fechas_ocupadas)}

HOY: ${ctx.hoy}`;

return [{
  json: {
    groq_payload: {
      model: 'llama-3.1-8b-instant',
      max_tokens: 300,
      temperature: 0.7,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userMsg }
      ]
    }
  }
}];
